INSERT INTO formations (id_formation, titre, description, duree, prix, categorie, date_debut, places_disponibles, created_at, updated_at, deleted_at, benefices, id_pays) SELECT gen_random_uuid(), v.* FROM (VALUES ('Gestion prévisionnelle des emplois et compétences', 'Formation sur l’anticipation des besoins RH et cartographie des compétences.', 5, 250000.00, 'entreprise', '2026-06-05', 30, '2026-01-14 12:37:32', '2026-02-18 23:44:04', NULL, E'--- OBJECTIFS ---\n• Anticiper les besoins en compétences\n• Réduire les risques liés aux écarts RH\n• Optimiser la gestion des talents et carrières\n• Améliorer la performance organisationnelle\n• Structurer une politique RH proactive\n• Mettre en place des outils de pilotage RH efficaces\n\n--- OBJECTIFS DÉTAILLÉS ---\nComprendre les principes et enjeux de la GPEC, identifier et cartographier les emplois et compétences, anticiper les écarts entre ressources disponibles et besoins futurs, mettre en place des outils de pilotage RH performants et élaborer des plans d’action RH adaptés.\n\n--- PRÉREQUIS ---\nConnaissances de base en gestion des ressources humaines. Une expérience préalable en management ou RH est un atout mais non obligatoire.\n\n--- CONTENU ---\nModule 1 : Fondamentaux de la GPEC\nModule 2 : Analyse des Emplois et Compétences\nModule 3 : Diagnostic et Anticipation\nModule 4 : Outils et Dispositifs GPEC\nModule 5 : Plan d’Action GPEC\n\n--- NIVEAU ---\nTous niveaux\n\n--- PUBLIC ---\nResponsables RH, managers, dirigeants, consultants en organisation, étudiants en gestion des ressources humaines.\n\n--- MÉTHODES ---\nApports conceptuels ciblés, études de cas réels, exercices pratiques, ateliers interactifs, simulations et échanges d’expériences, supports opérationnels fournis.\n\n--- SUPPORTS ---\nRéférentiels de compétences, grilles d’évaluation, logiciels RH, tableurs Excel, études de cas, supports PDF et modèles pratiques.\n\n--- CERTIFICATION ---\nAttestation de participation remise par ISD Groupe', 'ba52f30c-c061-41b8-b0f7-afa6eca6fa76')) AS v(titre, description, duree, prix, categorie, date_debut, places_disponibles, created_at, updated_at, deleted_at, benefices, id_pays) WHERE NOT EXISTS (SELECT 1 FROM formations f WHERE f.titre = v.titre AND f.date_debut = v.date_debut::date);
